import React from 'react';
import composeRefs from '../../../util/composeRefs';

const PopperBoundaryContext = React.createContext<HTMLElement | null>(null);

if (__DEV__) {
  PopperBoundaryContext.displayName = 'PopperBoundaryContext';
}

export const usePopperBoundaryContext = () => React.useContext(PopperBoundaryContext);

export const PopperBoundary = React.forwardRef<React.ComponentRef<'div'>, React.ComponentPropsWithoutRef<'div'>>(
  (props, ref) => {
    const [el, setEl] = React.useState<HTMLDivElement | null>(null);
    const mergedRef = React.useMemo(() => composeRefs(ref, node => setEl(node)), [ref]);
    return (
      <PopperBoundaryContext.Provider value={el}>
        <div ref={mergedRef} {...props} />
      </PopperBoundaryContext.Provider>
    );
  },
);
